at::Tensor conv2d_relu_hard_swish_impl_npu(const at::Tensor& x,
                                           const at::Tensor& weight,
                                           c10::optional<at::Tensor> bias_opt) {
    // x: [N, Cin, H, W], weight: [Cout, Cin, K, K], bias: [Cout] or None
    int64_t N = x.size(0);
    int64_t Cout = weight.size(0);
    int64_t H = x.size(2);
    int64_t W = x.size(3);
    int64_t K = weight.size(2);
    int64_t Hout = (H - K) + 1;
    int64_t Wout = (W - K) + 1;

    at::Tensor y = at::empty({N, Cout, Hout, Wout}, x.options());

    if (bias_opt.has_value()) {
        at::Tensor bias = bias_opt.value();
        EXEC_NPU_CMD(aclnnConv2dReluHardSwishCustom, x, weight, bias, y);
    } else {
        // Pass an empty tensor for optional bias
        at::Tensor bias = at::empty({0}, x.options());
        EXEC_NPU_CMD(aclnnConv2dReluHardSwishCustom, x, weight, bias, y);
    }
    return y;
}

